package com.cho2hand.marketplace.entity.trust; import jakarta.persistence.*; import java.time.Instant;
@Entity @Table(name="listing_transactions") public class ListingTransaction {@Id @GeneratedValue(strategy=GenerationType.IDENTITY) @Column(name="transaction_id") private Long id;@Column(name="listing_id") private Long listingId;@Column(name="buyer_user_id") private Long buyerUserId;private String status;@Column(name="confirmed_at") private Instant confirmedAt;@Column(name="seller_confirmed_at") private Instant sellerConfirmedAt;@Column(name="buyer_confirmed_at") private Instant buyerConfirmedAt;@Column(name="created_at") private Instant createdAt;@PrePersist void created(){createdAt=Instant.now();}public Long getId(){return id;}public Long getListingId(){return listingId;}public void setListingId(Long v){listingId=v;}public Long getBuyerUserId(){return buyerUserId;}public void setBuyerUserId(Long v){buyerUserId=v;}public String getStatus(){return status;}public Instant getConfirmedAt(){return confirmedAt;}public Instant getSellerConfirmedAt(){return sellerConfirmedAt;}public Instant getBuyerConfirmedAt(){return buyerConfirmedAt;}public void setStatus(String v){status=v;}public void setConfirmedAt(Instant v){confirmedAt=v;}public void setSellerConfirmedAt(Instant v){sellerConfirmedAt=v;}public void setBuyerConfirmedAt(Instant v){buyerConfirmedAt=v;}}
